// ─── Helpers ────────────────────────────────────────────────
function normalizePhone(raw) {
  if (!raw) return '';
  const d = String(raw).replace(/\D/g, '');
  if (d.length === 10) return '+1' + d;
  if (d.length === 11 && d[0] === '1') return '+' + d;
  if (d.length > 6) return '+' + d;
  return '+1' + d;
}

function parseName(name) {
  const parts = (name || 'Customer').trim().split(/\s+/);
  return { first: parts[0] || 'Customer', last: parts.slice(1).join(' ') || '' };
}

function itemsToNote(items) {
  if (!Array.isArray(items) || !items.length) return '  (no items recorded)';
  return items
    .map(i => '  ' + (i.quantity || 1) + 'x ' + i.name + ' \u2014 $' + parseFloat(i.price || 0).toFixed(2))
    .join('\n');
}

function itemsForSms(items) {
  if (!Array.isArray(items) || !items.length) return '* (no items)';
  return items
    .map(i => '* ' + i.name + ' x' + (i.quantity || 1) + ' - $' + parseFloat(i.price || 0).toFixed(2))
    .join('\n');
}

function fmtTime(iso) {
  try {
    return new Date(iso).toLocaleString('en-CA', {
      timeZone: 'America/Toronto',
      dateStyle: 'medium',
      timeStyle: 'short'
    });
  } catch (e) {
    return String(iso || new Date().toISOString());
  }
}

function fmtTimeShort(iso) {
  try {
    return new Date(iso || new Date()).toLocaleString('en-CA', {
      timeZone: 'America/Toronto',
      hour: 'numeric',
      minute: '2-digit',
      hour12: true
    });
  } catch (e) {
    return '';
  }
}

function calcReadySlots(iso) {
  try {
    const base = new Date(iso || new Date());
    return [30, 60, 90].map(offset => {
      const t = new Date(base.getTime() + offset * 60000);
      return t.toLocaleString('en-CA', {
        timeZone: 'America/Toronto',
        hour: 'numeric',
        minute: '2-digit',
        hour12: true
      });
    }).join('  |  ');
  } catch (e) {
    return '';
  }
}

function fmtInstructions(raw) {
  if (!raw || raw === 'None') return 'None';
  // capitalise first letter, replace key-value separators
  return raw.trim()
    .replace(/^(spice|spicy|heat)\s*:\s*/i, 'Spice Level: ')
    .replace(/^(allergy|allergies)\s*:\s*/i, 'Allergy: ')
    .replace(/^(note|notes|special)\s*:\s*/i, '')
    .replace(/^./, c => c.toUpperCase());
}

// ─── Parse incoming payload ──────────────────────────────────
// n8n wraps the body under .body when responseMode is onReceived
const b = $input.first().json.body ?? $input.first().json;

const phone      = normalizePhone(b.phone_number);
const name       = parseName(b.customer_name);
const oType      = b.order_type || 'pickup';
const oLabel     = oType.replace(/_/g, '-').toUpperCase();
const subtotal   = parseFloat(b.total_amount || 0);
const gst        = Math.round(subtotal * 0.05 * 100) / 100;
const grandTotal = Math.round((subtotal + gst) * 100) / 100;
const orderId    = b.order_id || 'PS-UNKNOWN';
const waitTime   = b.wait_time || '20-30 minutes';
const items      = b.items || [];
const instructions = fmtInstructions(b.special_instructions);
const readySlots = calcReadySlots(b.timestamp);

// ─── Build GHL contact note ──────────────────────────────────
const sep = '\u2500'.repeat(34);
let noteLines = [
  '\uD83D\uDCDE VOICE ORDER \u2014 ' + orderId,
  sep,
  'Date:     ' + fmtTime(b.timestamp),
  'Type:     ' + oLabel,
  '',
  'ITEMS:',
  itemsToNote(items),
  '',
  'SUBTOTAL: $' + subtotal.toFixed(2) + ' CAD',
  'GST (5%): $' + gst.toFixed(2),
  'TOTAL:    $' + grandTotal.toFixed(2) + ' CAD',
  'WAIT:     ' + waitTime
];
if (b.delivery_address)     noteLines.push('', 'DELIVER TO: ' + b.delivery_address);
if (b.special_instructions) noteLines.push('', 'SPECIAL: '   + b.special_instructions);
noteLines.push(sep, 'via Parkash Sweets Voice Agent (Sierra)');

// ─── Build SMS notification ───────────────────────────────────
const orderTypeFriendly = oType === 'dine_in' ? 'dine-in' : oType;
const fullName = (name.first + (name.last ? ' ' + name.last : '')).trim();
const timeStr  = fmtTimeShort(b.timestamp);

const smsText =
  '\uD83D\uDEA8 NEW ORDER \uD83D\uDEA8\n' +
  'Restaurant: Parkash Sweets\n' +
  'Address: PARKASH_SWEETS_ADDRESS\n\n' +
  'Name: ' + fullName + '\n' +
  'Phone: ' + phone + '\n' +
  'Type: ' + orderTypeFriendly + '\n\n' +
  'Order Id: ' + orderId + '\n\n' +
  'ITEMS:\n' +
  itemsForSms(items) + '\n\n' +
  'Subtotal: $' + subtotal.toFixed(2) + '\n' +
  'GST (5%): $' + gst.toFixed(2) + '\n' +
  'TOTAL: $' + grandTotal.toFixed(2) + '\n\n' +
  'Instructions: ' + instructions + '\n\n' +
  'Time: ' + timeStr + '\n' +
  'Ready By: ' + readySlots + '\n\n' +
  'Thank you! \uD83D\uDE4F';

// ─── Contact body for GHL upsert ─────────────────────────────
const contactBody = {
  locationId: 'uc3GK4buCjDTCkedqWyy',
  firstName:  name.first,
  lastName:   name.last,
  phone:      phone,
  source:     'Voice Agent \u2014 Parkash Sweets',
  tags:       ['parkash-customer', oType.replace(/_/g, '-')]
};

return [{
  json: {
    orderId,
    phone,
    firstName:   name.first,
    orderType:   oType,
    noteText:    noteLines.join('\n'),
    smsText,
    contactBody
  }
}];
